import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{n as i,t as a}from"./chunks/template-generator-advanced.CleIDHrl.js";const o=JSON.parse(`{"title":"Ein Projekt erstellen","description":"Eine Schritt-für-Schritt-Anleitung, wie man ein neues Mod-Projekt mit dem Fabric Template Mod Generator erstellt.","frontmatter":{"title":"Ein Projekt erstellen","description":"Eine Schritt-für-Schritt-Anleitung, wie man ein neues Mod-Projekt mit dem Fabric Template Mod Generator erstellt.","authors":["Cactooz","IMB11","radstevee","Thomas1034"],"resources":{"https://fabricmc.net/develop/template/":"Fabric Vorlagenmod Generator","https://fabricmc.net/develop/":"Entwickeln mit Fabric Website"},"files":[]},"headers":[],"relativePath":"de_de/develop/getting-started/creating-a-project.md","filePath":"translated/de_de/develop/getting-started/creating-a-project.md","lastUpdated":1774711188000}`);var s={name:`de_de/develop/getting-started/creating-a-project.md`};function c(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Ein Projekt erstellen <a class="header-anchor" href="#h1" aria-label="Permalink to “Ein Projekt erstellen”">​</a></h1><p>Fabric bietet eine einfache Möglichkeit, ein neues Mod-Projekt mit dem Fabric Template Mod Generator zu erstellen - wenn du möchtest, kannst du ein neues Projekt auch manuell erstellen, indem du das Beispiel-Mod-Repository verwendest, dann solltest du den Abschnitt <a href="#manuelle-projekterstellung">Manuelle Projekterstellung</a> lesen.</p><h2 id="generating-a-project" tabindex="-1">Erstellung eines Projekts <a class="header-anchor" href="#generating-a-project" aria-label="Permalink to “Erstellung eines Projekts”">​</a></h2><p>Du kannst den <a href="https://fabricmc.net/develop/template/" target="_blank" rel="noreferrer">Fabric Template Mod Generator</a> verwenden, um ein neues Projekt für deine Mod zu generieren - du solltest die erforderlichen Felder ausfüllen, wie beispielsweise den Paketnamen und den Mod-Namen, sowie die Minecraft-Version, für die du entwickeln möchtest.</p><p>Der Paketname sollte kleingeschrieben, durch Punkte getrennt und eindeutig sein, um Konflikte mit den Paketen anderer Programmierer zu vermeiden. Er ist typischerweise wie eine umgedrehte Internet-Domain formatiert, beispielsweise wie <code>com.example.example-mod</code>.</p><div class="warning custom-block"><p class="custom-block-title">WICHTIG</p><p>Stelle sicher, dass du dir deine Mod-ID merkst! Wenn du in dieser Dokumentation, insbesondere in Dateipfaden, auf <code>example-mod</code> stoßt, musst du dies durch deine eigene ersetzen.</p><p>Wenn deine Mod-ID beispielsweise <strong><code>my-cool-mod</code></strong> lautet, verwende anstelle von <em><code>resources/assets/example-mod</code></em> <strong><code>resources/assets/my-cool-mod</code></strong>.</p></div><p><img src="/assets/develop/getting-started/template-generator.png" alt="Vorschau des Generators" loading="lazy"></p><p>Wenn du entweder Kotlin oder die Yarn-Mappings von Fabric anstelle der standardmäßigen Mojang-Mapping verwenden oder Datengeneratoren hinzufügen willst, kannst du die entsprechenden Optionen im Abschnitt <code>Advanced Options</code> auswählen.</p><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>Die auf dieser Website angegebenen Codebeispiele verwenden <a href="./../porting/mappings/#mappings">die offiziellen Namen von Mojang</a>. Wenn dein Mod nicht dieselben Mappings verwendet, in denen diese Dokumente geschrieben sind, musst du die Beispiele mithilfe von Websites wie <a href="https://mappings.dev/" target="_blank" rel="noreferrer">mappings.dev</a> oder <a href="https://linkie.shedaniel.dev/mappings?namespace=yarn&amp;translateMode=ns&amp;translateAs=mojang_raw&amp;search=" target="_blank" rel="noreferrer">Linkie</a> konvertieren.</p></div><p><img src="/assets/develop/getting-started/template-generator-advanced.png" alt="Der Abschnitt &quot;Advanced options&quot;" loading="lazy"></p><p>Nachdem du die erforderlichen Felder ausgefüllt hast, klickst du auf die Schaltfläche <code>Generate</code>. Der Generator erstellt dann ein neues Projekt in Form einer ZIP-Datei für dich.</p><p>Du solltest diese ZIP-Datei an einem Ort deiner Wahl entpacken und dann den entpackten Ordner in deiner Entwicklungsumgebung öffnen.</p><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>Du solltest diese Regeln befolgen, wenn du den Pfad zu deinem Projekt auswählst:</p><ul><li>Vermeide Cloudspeicher-Verzeichnisse (zum Beispiel Microsoft OneDrive)</li><li>Vermeide nicht-ASCII Zeichen (zum Beispiel Emoji, akzentuierte Buchstaben)</li><li>Vermeide Leerzeichen</li></ul><p>Ein Beispiel eines &quot;guten&quot; Pfad könnte sein: <code>C:\\Projects\\YourProjectName</code></p></div><h2 id="manual-project-creation" tabindex="-1">Manuelle Projekterstellung <a class="header-anchor" href="#manual-project-creation" aria-label="Permalink to “Manuelle Projekterstellung”">​</a></h2><div class="info custom-block"><p class="custom-block-title">VORAUSSETZUNGEN</p><p>Du musst <a href="https://git-scm.com/" target="_blank" rel="noreferrer">Git</a> installiert haben, um das Beispiel-Mod-Repository klonen zu können.</p></div><p>Wenn du den Fabric Template Mod Generator nicht verwenden kannst, kannst du ein neues Projekt manuell erstellen, indem du folgende Schritte befolgst.</p><p>Klone zunächst das Beispiel-Mod-Repository mit Git:</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/FabricMC/fabric-example-mod/</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> example-mod</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Dadurch wird das Repository in einen neuen Ordner mit dem Namen <code>example-mod</code> geklont.</p><p>Anschließend solltest du den Ordner <code>.git</code> aus dem geklonten Repository löschen und das Projekt öffnen. Wenn der Ordner <code>.git</code> nicht angezeigt wird, solltest du die Option zur Anzeige versteckter Dateien in deinem Dateimanager aktivieren.</p><p>Sobald du das Projekt in deiner Entwicklungsumgebung geöffnet hast, sollte es automatisch die Gradle-Konfiguration des Projekts laden und die notwendigen Einrichtungsaufgaben durchführen.</p><p>Wie bereits erwähnt, solltest du, wenn du eine Benachrichtigung über ein Gradle-Build-Skript erhältst, auf die Schaltfläche <code>Import Gradle Project</code> klicken.</p><h3 id="modifying-the-template" tabindex="-1">Die Vorlage bearbeiten <a class="header-anchor" href="#modifying-the-template" aria-label="Permalink to “Die Vorlage bearbeiten”">​</a></h3><p>Sobald das Projekt importiert wurde, solltest du die Details des Projekts so ändern, dass sie mit deiner Mod übereinstimmen:</p><ul><li>Ändere die Datei <code>gradle.properties</code> des Projekts, um die Eigenschaften <code>maven_group</code> und <code>archive_base_name</code> an die Details deiner Mod anzupassen.</li><li>Ändere die Datei <code>fabric.mod.json</code>, um die Eigenschaften <code>id</code>, <code>name</code> und <code>description</code> an die Details deiner Mod anzupassen.</li><li>Stelle sicher, dass die Versionen von Minecraft, den Mappings, des Loaders und Loom - die alle über <a href="https://fabricmc.net/develop/" target="_blank" rel="noreferrer">https://fabricmc.net/develop/</a> abgefragt werden können - mit den Versionen übereinstimmen, die du ansprechen möchtest.</li></ul><p>Du kannst natürlich den Paketnamen und die Hauptklasse der Mod ändern, um die Details deiner Mod anzupassen.</p>`,26)]])}var l=r(s,[[`render`,c]]);export{o as __pageData,l as default};